// // If hc is 11, then l should be 1; if hc is 10, then l should be 0; if hc is 01, then l should be 1; if hc is 00, then l should be 0.
module top_module (
    input h,
    input c,
    output reg l
);
    always @(*) begin
        case ({h, c})
            2'b11: l = 1'b0;
            2'b10: l = 1'b1;
            2'b01: l = 1'b0;
            2'b00: l = 1'b1;
        endcase
    end
endmodule
